INSERT INTO aprendizagens_essenciais (id, nivel_ensino, disciplina, ano_serie, bimestre, codigo, descricao, created_at) VALUES
(1, 'Ensino Fundamental: Anos Finais', 'Arte', '6º Ano', NULL, 'AE1', 'Diferenciar movimentos coreográficos em danças folclóricas de diferentes épocas.', NOW()),
(2, 'Ensino Fundamental: Anos Finais', 'Arte', '6º Ano', NULL, 'AE2', 'Experimentar composições coreográficas autorais com base em elementos das danças folclóricas brasileiras.', NOW()),
(3, 'Ensino Fundamental: Anos Finais', 'Arte', '6º Ano', NULL, 'AE3', 'Analisar os gêneros da música brasileira a partir de seus contextos de produção, circulação e apreciação.', NOW()),
(4, 'Ensino Fundamental: Anos Finais', 'Arte', '6º Ano', NULL, 'AE4', 'Criar composições musicais, por meio da voz, sons corporais e instrumentos não convencionais, traduzindo-as em partituras criativas.', NOW()),
