(10, 'Ensino Fundamental: Anos Finais', 'Arte', '8º Ano', NULL, 'AE1', 'Analisar composições de danças coletivas de diferentes matrizes culturais brasileiras para apreciá-las.', NOW()),
(11, 'Ensino Fundamental: Anos Finais', 'Arte', '8º Ano', NULL, 'AE2', 'Explorar as variações dos fatores do movimento (tempo, fluência e espaço) explorando-os na prática da dança.', NOW()),
