(14, 'Ensino Fundamental: Anos Finais', 'Arte', '8º Ano', NULL, 'AE5', 'Analisar os elementos das músicas indígenas como uma das matrizes culturais brasileiras, utilizando canções, jogos e apreciando as composições.', NOW()),
(15, 'Ensino Fundamental: Anos Finais', 'Arte', '8º Ano', NULL, 'AE6', 'Expressar ideias musicais de forma individual e coletiva, por meio da improvisação e composição com voz, sons corporais e instrumentos variados.', NOW()),
(16, 'Ensino Fundamental: Anos Finais', 'Arte', '9º Ano', NULL, 'AE1', 'Analisar o uso de elementos cênicos (figurino, cenário, iluminação, espaços e tecnologias digitais) nos contextos de criação coreográfica e apresentações de dança.', NOW()),
(17, 'Ensino Fundamental: Anos Finais', 'Arte', '9º Ano', NULL, 'AE2', 'Explorar brincadeiras e jogos no processo de criação coreográfica em dança contemporânea, integrando tecnologias digitais nas apresentações.', NOW()),
(18, 'Ensino Fundamental: Anos Finais', 'Arte', '9º Ano', NULL, 'AE3', 'Analisar funções e estéticas dos diferentes gêneros da música popular brasileira e estrangeira, considerando seu contexto histórico e social.', NOW()),
