(20, 'Ensino Médio', 'Arte', '1ª Série', NULL, 'AE1', 'Analisar o funcionamento das linguagens artísticas em suas dimensões visuais, verbais, sonoras e gestuais para a interpretação e a produção de discursos presentes na mídia e em obras de diversos artistas.', NOW()),
(21, 'Ensino Médio', 'Arte', '1ª Série', NULL, 'AE2', 'Utilizar as linguagens artísticas, analisando sua aplicabilidade e sua função como fenômeno social, cultural, histórico, político e econômico.', NOW()),
