(24, 'Ensino Médio', 'Arte', '1ª Série', NULL, 'AE5', 'Experimentar processos de criação em diversas linguagens artísticas, considerando seus aspectos formais, seus funcionamentos e a produção de sentido, em diferentes contextos.', NOW()),
(25, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE1', 'Compor e decompor números naturais de diferentes ordens, reconhecendo as características do sistema de numeração decimal.', NOW()),
(26, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE2', 'Comparar e ordenar números naturais de diferentes ordens, utilizando, inclusive, a reta numérica como suporte.', NOW()),
(27, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE3', 'Resolver problemas envolvendo as quatro operações fundamentais com números naturais, por meio de estratégias variadas.', NOW()),
(28, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE4', 'Resolver problemas envolvendo múltiplos e divisores de números naturais, utilizando-os para ampliar as estratégias de cálculo.', NOW()),
(29, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE5', 'Resolver problemas envolvendo cálculo da fração de uma quantidade, cujo resultado é um número natural.', NOW()),
(30, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE6', 'Comparar e ordenar frações, utilizando equivalência, representações visuais e a reta numérica como apoio.', NOW()),
(31, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE7', 'Resolver problemas que envolvam adição ou subtração de números racionais positivos na representação fracionária, por meio de estratégias diversas.', NOW()),
(32, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE8', 'Classificar polígonos, considerando lados, vértices e ângulos, diferenciando os regulares dos não regulares.', NOW()),
