(34, 'Ensino Fundamental: Anos Finais', 'Matemática', '6º Ano', NULL, 'AE10', 'Classificar quadriláteros em relação às medidas dos lados e ângulos, comparando suas classes.', NOW()),
(35, 'Ensino Fundamental: Anos Finais', 'Matemática', '7º Ano', NULL, 'AE1', 'Resolver problemas que envolvam múltiplos e divisores de números naturais, em contextos reais.', NOW()),
(36, 'Ensino Fundamental: Anos Finais', 'Matemática', '7º Ano', NULL, 'AE2', 'Comparar e ordenar números inteiros, utilizando, inclusive, a reta numérica como recurso.', NOW()),
