(38, 'Ensino Fundamental: Anos Finais', 'Matemática', '7º Ano', NULL, 'AE4', 'Comparar e ordenar frações associadas às ideias de partes de inteiros, resultado da divisão, razão e operador, utilizando, inclusive, a reta numérica como apoio.', NOW()),
(39, 'Ensino Fundamental: Anos Finais', 'Matemática', '7º Ano', NULL, 'AE5', 'Resolver problemas envolvendo as quatro operações fundamentais com frações, por meio de estratégias diversas de cálculo e representações visuais.', NOW()),
(40, 'Ensino Fundamental: Anos Finais', 'Matemática', '7º Ano', NULL, 'AE6', 'Resolver problemas envolvendo as quatro operações fundamentais com números racionais nas formas fracionária e decimal, estabelecendo relações entre essas representações.', NOW()),
